                        correctedCount++;  // This is now effectively atomic due to sequencing
                        correctedCountElement.textContent = correctedCount;
                        resolve();  // Resolve the promise after the update
                    }, 100);  // 100ms delay to simulate asynchronous work
                });
            });
        });
    </script>
