        document.getElementById('buggy-count').textContent = buggyCount;
      }, 100);  // Delay of 100ms to simulate asynchronous work
    });

    // Corrected version implementation
    let correctedCount = 0;
    let queue = [];  // Queue to hold pending updates
    let isProcessing = false;  // Flag to track if an update is in progress

    function processQueue() {
      if (isProcessing || queue.length === 0) return;  // If processing or queue is empty, stop
      isProcessing = true;
      setTimeout(() => {
        correctedCount++;  // Increment the count
        document.getElementById('corrected-count').textContent = correctedCount;
        isProcessing = false;  // Mark as not processing
        processQueue();  // Check and process the next item in the queue
      }, 100);  // Same delay as buggy version
    }

    document.getElementById('corrected-button').addEventListener('click', () => {
      queue.push(true);  // Add a task to the queue (just a placeholder)
      processQueue();  // Start processing if not already
    });
