        const buggyButton = document.getElementById('buggy-button');

        buggyButton.addEventListener('click', () => {
            setTimeout(() => {
                let current = buggyCount;  // Read the current value
                current += 1;              // Modify it
                buggyCount = current;      // Write it back
                buggyDisplay.textContent = buggyCount;  // Update the display
            }, 0);  // Asynchronous delay
        });

        // Corrected version
        let correctedCount = 0;  // Shared count variable
        let currentPromise = Promise.resolve();  // Start with a resolved promise
        const correctedDisplay = document.getElementById('corrected-count');
        const correctedButton = document.getElementById('corrected-button');

        correctedButton.addEventListener('click', () => {
            currentPromise = currentPromise.then(() => {
                return new Promise(resolve => {
                    setTimeout(() => {
                        correctedCount += 1;  // Directly increment (now serialized)
                        correctedDisplay.textContent = correctedCount;  // Update the display
                        resolve();  // Resolve the promise after update
                    }, 0);  // Asynchronous delay, but chained
                });
            });
        });
    </script>
